request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?normalizedId WHERE {
  ?org tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:normalizedId ?normalizedId .

  {
    ?choreo a bboExt:Choreography .
    ?task a bboExt:ChoreographyTask .
    ?task tai:belongsTo ?choreo .
    ?task bboExt:loopType "MultiInstanceParallel" .
    FILTER EXISTS { ?task tai:belongsTo ?choreo . }
  }
  UNION
  {
    ?choreo a bboExt:Choreography .
    ?pg a bboExt:ParallelGateway .
    ?pg tai:belongsTo ?choreo .
  }
}
ORDER BY ?created
LIMIT 25
